module top_module(clock, reset_n, D, Q);input clock, reset_n;
input  [3:0] D;
output [3:0] Q;
reg    [3:0] unused_tmp; 


  always @(posedge clock)
    begin
      if (reset_n)
        unused_tmp <= 4'b0000;
      else
        unused_tmp <= unused_tmp + D;
    end
assign Q = unused_tmp;
endmodule
